32	  INTEGRATION_DEMO_BASE_URL: 'https://httpbin.org/anything',
33	  INTEGRATION_DEMO_API_TOKEN: 'latam-demo-token',
34	  INTEGRATION_DEMO_WEBHOOK_SECRET: DEMO_SECRET,
35	};
