1	#!/usr/bin/env node
2	/**
3	 * Scenario runner TEMPLATE — copy this to `sdk/org/scenarios/<id>/run.mjs` and fill in the Acts.
4	 * It bakes in every hardening pattern the campaigns learned the hard way (see the harness API +
5	 * hardening patterns in automation/instances/scenario-campaign/prompt.common.md): per-Act
6	 * checkpointing + resume, a keepalive pinger, a resilient `send`
7	 * that survives a full pod restart, a scripted ask answerer, attachment + live-app + inbound helpers,
8	 * and trace-based assertions.
9	 *
10	 * NOTE: `ThingSession` now self-heals SESSION EVICTION natively (a long turn's sub-sessions can push
11	 * a small pod past MAX_SESSIONS): pullEvents treats a post-work 404 as turn-complete, and it
12	 * re-establishes an evicted session before the next send. The `thing.send` wrapper below is the extra
13	 * belt for a FULL pod roll/restart. For a session-heavy scenario, also raise the cap on the test pod:
14	 *   ssh … 'kubectl set env deployment/lmthing MAX_SESSIONS=25 -n user-<id>'
15	 *
16	 *   cd sdk/org/scenarios/harness && node ../<id>/run.mjs [--acts=1,2,3] [--fresh]
17	 *
18	 * Replace every `SCENARIO_*` below, then write your Acts where marked.
19	 */
20	import { existsSync, mkdirSync, readFileSync, writeFileSync } from 'node:fs';
21	import { createHmac } from 'node:crypto';
22	import { getUser } from '../harness/provision.mjs';
23	import { Pod } from '../harness/lib/pod.mjs';
24	import { ThingSession } from '../harness/lib/thing.mjs';
25	import { Report } from '../harness/lib/report.mjs';
26	import { mergePodEnv, waitPodReady, waitPodSettled } from '../harness/lib/gateway.mjs';
27	import { SDK_ORG } from '../harness/lib/paths.mjs';
28	
29	// ── config — EDIT THESE ─────────────────────────────────────────────────────────
30	const ID = 'SCENARIO_ID'; // e.g. '06-something'
31	const TITLE = 'SCENARIO_TITLE';
32	const LABEL = 'SCENARIO_LABEL'; // provision.mjs label (disposable user prefix)
33	const PROJECT = 'SCENARIO_PROJECT'; // the project id the scenario runs in ('user' = default)
34	/** Any integration/env secrets the scenario needs, loaded BEFORE the first session. */
35	const POD_ENV = {
36	  // INTEGRATION_DEMO_BASE_URL: 'https://httpbin.org/anything',
37	  // INTEGRATION_DEMO_API_TOKEN: 'demo-token',
38	  // INTEGRATION_DEMO_WEBHOOK_SECRET: 'demo-hmac-secret',
39	};
40	
41	const RESULTS = `${SDK_ORG}/scenarios/${ID}/results`;
42	const CHECKPOINT = `${RESULTS}/checkpoint.json`;
43	const argActs = (process.argv.find((a) => a.startsWith('--acts=')) ?? '').slice(7);
44	const ACTS = argActs ? argActs.split(',').map(Number) : [1, 2, 3, 4];
45	const FRESH = process.argv.includes('--fresh');
46	const sleep = (ms) => new Promise((r) => setTimeout(r, ms));
47	const now = () => Date.now();
48	
49	// ── checkpoint (resume from the last good Act) ──────────────────────────────────
50	function loadCheckpoint() {
51	  if (FRESH || !existsSync(CHECKPOINT)) return { acts: {}, sessionId: null };
52	  try { return JSON.parse(readFileSync(CHECKPOINT, 'utf8')); } catch { return { acts: {}, sessionId: null }; }
53	}
54	function saveCheckpoint(cp) {
55	  mkdirSync(RESULTS, { recursive: true });
56	  writeFileSync(CHECKPOINT, JSON.stringify(cp, null, 2));
57	  console.log(`\n💾 checkpoint → ${CHECKPOINT}`);
58	}
59	
60	// ── scripted asks: approve/deny consent, settle any other ask so a run never hangs ──
61	const scriptedOnAsk = (consent) => (d) => {
62	  if (d?.type === 'ConsentCard') return consent;
63	  if (d?.type) return {}; // settle Forms/other asks with an empty submission
64	  return undefined;
65	};
66	
67	// ── signed inbound helper (a provider-shaped, HMAC-signed webhook to the pod) ────
68	function signedInbound(pod, path, body, secret, header = 'x-demo-signature') {
69	  const raw = typeof body === 'string' ? body : JSON.stringify(body);
70	  const sig = 'sha256=' + createHmac('sha256', secret).update(raw).digest('hex');
71	  return pod.inbound(path, raw, { [header]: sig });
72	}
73	
74	// ── fixture-token assertion (the ONLY proof a fixture was actually READ) ────────
75	// Each fixture in fixtures/links.md carries a token that appears in that file and NOWHERE else.
76	// A token in the chat reply proves nothing — the model can guess. A token in a DB ROW or a SPACE
77	// FILE proves the bytes were ingested: the image through vision, the audio through transcription,
78	// the pdf/xlsx through readDocument. Assert every fixture this way, or it is dead weight.
79	async function assertTokenInState(report, pod, projectId, { fixture, token, tables = [], spaces = true }) {
80	  const rx = new RegExp(token.replace(/[.*+?^${}()|[\]\\]/g, '\\$&'), 'i');
81	  const hits = [];
82	  const manifest = await pod.appManifest(projectId).catch(() => ({}));
83	  const names = (manifest?.tables ?? []).map((t) => (typeof t === 'string' ? t : t.name));
84	  for (const name of tables.length ? tables : names) {
85	    const rows = (await pod.appData(projectId, name).catch(() => ({ rows: [] }))).rows ?? [];
86	    if (rows.some((r) => rx.test(JSON.stringify(r)))) hits.push(`db:${name}`);
87	  }
88	  if (spaces && !hits.length) {
89	    const tree = await pod.fsTree().catch(() => null);
90	    const files = JSON.stringify(tree ?? '');
91	    if (rx.test(files)) hits.push('space-file');
92	  }
93	  report.check(
94	    `${fixture}: its unique token "${token}" landed in REAL STATE (not prose)`,
95	    hits.length > 0,
96	    hits.length ? hits.join(', ') : 'NOT FOUND in any row or space file — the file was never read',
97	  );
98	  return hits;
99	}
100	
101	// ── the app's OWN api routes — the layer the USER actually sees ─────────────────
102	// A dashboard can render 0 / €0.00 on every tile while /app/data/<table> happily returns all its
103	// rows, because the page's own aggregation route 500s. That really happened. Assert the routes the
104	// PAGES fetch, not just the raw data API.
105	async function assertAppApi(report, pod, projectId, routes = []) {
106	  for (const [route, check] of Object.entries(routes)) {
107	    const res = await pod.appApi(projectId, route, undefined, 'GET').catch((e) => ({ status: 0, body: String(e) }));
108	    const ok = res.status === 200 && (typeof check === 'function' ? check(res.body) : true);
109	    report.check(`app's own route GET /${projectId}/api/${route} → 200 + real data`, ok, `status ${res.status}: ${JSON.stringify(res.body).slice(0, 160)}`);
110	  }
111	}
112	
113	// ── project-app assertion helper (build + read real rows) ────────────────────────
114	// A real live-project app: compile it and confirm real assets came out, then read its DB rows.
115	// (`built` lives at manifest.build.built and only reflects the LAST compile — so build explicitly
116	//  and read the POST result, which carries assetManifest + routes — see the harness gotchas in the campaign prompt.)
117	async function assertLiveApp(report, pod, projectId, { minRowTables = {} } = {}) {
118	  const build = await pod.appBuild(projectId).catch((e) => ({ built: false, error: String(e) }));
119	  const assets = build?.assetManifest ?? [];
120	  report.check('app compiles (built:true) with real JS assets', build?.built === true && assets.some((a) => /\.js$/.test(a)), JSON.stringify({ built: build?.built, assets }).slice(0, 200));
121	  report.check('app serves ≥1 page route', (build?.routes?.length ?? 0) >= 1, (build?.routes ?? []).map((x) => x.routePath).join(', '));
122	  const page = await pod.appPage(projectId).catch((e) => ({ status: 0, body: String(e) }));
123	  report.check(`/app/${projectId}/ serves 200 HTML`, page.status === 200 && String(page.body).includes('<!doctype'), `status ${page.status}, ${String(page.body).length} bytes`);
124	  // minRowTables: { <table-regex>: <min rows> } — assert real data landed (moved into the db).
125	  const manifest = await pod.appManifest(projectId).catch(() => ({}));
126	  const names = (manifest?.tables ?? []).map((t) => (typeof t === 'string' ? t : t.name));
127	  for (const [rx, min] of Object.entries(minRowTables)) {
128	    const t = names.find((n) => new RegExp(rx, 'i').test(n));
129	    const rows = t ? (await pod.appData(projectId, t).catch(() => ({ rows: [] }))).rows ?? [] : [];
130	    report.check(`table /${rx}/ has ≥${min} rows`, rows.length >= min, `${t ?? '(none)'}: ${rows.length} rows`);
131	  }
132	  return build;
133	}
134	
135	// ── main ────────────────────────────────────────────────────────────────────────
136	const report = new Report(ID, TITLE);
137	const cp = loadCheckpoint();
138	const t0 = now();
139	
140	const user = await getUser(LABEL);
141	console.log(`user ${user.email} (${user.userId}) → ${user.pod}`);
142	
143	const { changed } = await mergePodEnv(user.token, POD_ENV);
144	if (changed) { await waitPodReady(user.token); await waitPodSettled(user.token); }
145	
146	const pod = new Pod({ base: user.pod, token: user.token });
147	const projects = await pod.listProjects();
148	if (PROJECT !== 'user' && !(projects.projects ?? []).some((p) => (p.id ?? p) === PROJECT)) {
149	  await pod.createProject(PROJECT);
150	}
151	cp.projectId = PROJECT;
152	cp.user = { label: LABEL, email: user.email, userId: user.userId };
153	
154	const thing = new ThingSession(pod, { projectId: PROJECT, onAsk: scriptedOnAsk(true), verbose: true });
155	if (cp.sessionId && !FRESH) {
156	  try { await thing.resume(cp.sessionId); } catch { cp.sessionId = await thing.start(); }
157	} else {
158	  cp.sessionId = await thing.start();
159	}
160	saveCheckpoint(cp);
161	
162	// keep the pod warm so an idle scale-to-zero never kills the session mid-run
163	const keepalive = setInterval(() => {
164	  pod.req('POST', '/api/keepalive', {}).catch(() => pod.req('POST', '/api/compute/wake', {}).catch(() => {}));
165	}, 30_000);
166	keepalive.unref?.();
167	
168	// resilient send: survive a pod roll/restart (also exercises the auto-resume edge)
169	const _send = thing.send.bind(thing);
170	thing.send = async (content, opts = {}) => {
171	  for (let attempt = 0; ; attempt++) {
172	    try { return await _send(content, opts); }
173	    catch (e) {
174	      const msg = String(e?.body?.error ?? e?.message ?? '');
175	      const lost = e?.status === 404 || /unknown session|404/.test(msg);
176	      const errored = /entered error state/.test(msg);
177	      if ((!lost && !errored) || attempt >= 3) throw e;
178	      await waitPodReady(user.token).catch(() => {});
179	      for (let i = 0; i < 40; i++) { if (await pod.listProjects().then(() => true).catch(() => false)) break; await sleep(4_000); }
180	      if (lost && !errored) { try { await thing.resume(cp.sessionId); continue; } catch { /* fresh */ } }
181	      cp.sessionId = await thing.start(); saveCheckpoint(cp);
182	    }
183	  }
184	};
185	
186	const metrics = { tokens: { in: 0, out: 0 } };
187	const acc = (turn) => { metrics.tokens.in += turn.tokens.in; metrics.tokens.out += turn.tokens.out; return turn; };
188	
189	// ═══ ACT I ════════════════════════════════════════════════════════════════════
190	if (ACTS.includes(1)) {
191	  report.step('Act I — <name>', '<the contract this Act asserts>');
192	  const t = acc(await thing.send('<the user message>', { timeoutMs: 900_000 }));
193	  report.check('no eval/typecheck errors', t.errors.length === 0, JSON.stringify(t.errors).slice(0, 200));
194	  // report.check('delegated to <space>', thing.didDelegate('<space>'), t.delegates.join(', '));
195	  // ...assert on the trace + real side effects (files/rows/spaces), not the prose...
196	  cp.acts.I = { passed: report.passed };
197	  saveCheckpoint(cp);
198	}
199	
200	// ═══ ACT II / III / IV — same shape; gate each on ACTS.includes(n) + checkpoint ═══
201	// (Toggle scripted consent for a deny branch: thing.onAsk = scriptedOnAsk(false); ... reset to true.)
202	//
203	// ── Example: a file attachment → a live app with the data seeded in (the S06 pattern) ──
204	// const attachment = await pod.upload(`${SDK_ORG}/scenarios/${ID}/fixtures/notes.md`);
205	// report.check('file uploaded (kind=file)', attachment.kind === 'file', attachment.mediaType);
206	// // Attachments ride the WS path (HTTP /message drops them). THING hands the file to a specialist
207	// // via attachmentIds; the automator readDocument()s it and seeds rows via writeProjectTable(...,rows).
208	// const t = acc(await thing.sendWithAttachments('<the user message>', [attachment], { timeoutMs: 1_500_000 }));
209	// report.check('read the file (system-files)', thing.didDelegate('system-files'), t.delegates.join(', '));
210	// await assertLiveApp(report, pod, PROJECT, { minRowTables: { 'flight|itinerary': 5, 'accommodation|hotel': 6 } });
211	//
212	// ── Example: a LATER update changes the db (use a NEW fact NOT already in any seed) ──
213	// const before = JSON.stringify(await pod.appData(PROJECT, '<table>').catch(() => ({})));
214	// acc(await thing.send('Mark X as done and record confirmation "NEW-TOKEN-123".', { timeoutMs: 900_000 }));
215	// await sleep(4_000);
216	// const after = JSON.stringify(await pod.appData(PROJECT, '<table>').catch(() => ({})));
217	// report.check('the NEW fact landed in the db', !before.includes('new-token-123') && after.toLowerCase().includes('new-token-123'), 'before/after diff');
218	//
219	// ── Example: a signed inbound webhook fires a code-handler hook (0 LLM) ──
220	// const res = await signedInbound(pod, 'demo', { message: { message_id: 1, text: 'TIP: hello', chat: { id: 'c1' }, from: { id: 'u1' } } }, POD_ENV.INTEGRATION_DEMO_WEBHOOK_SECRET);
221	// report.check('inbound accepted (verify→emit)', res.status === 200 && res.body?.events >= 1, JSON.stringify(res.body));
222	
223	// ═══ verdict ══════════════════════════════════════════════════════════════════
224	const stats = thing.stats();
225	report.step('Whole-session invariants', 'no eval/typecheck errors; routing not degraded over the run');
226	report.check('zero eval/typecheck errors across the session', stats.errors === 0, `${stats.errors} errors`);
227	report.metric('wall clock', ((now() - t0) / 60_000).toFixed(1), ' min');
228	report.metric('total tokens (in/out)', `${metrics.tokens.in} / ${metrics.tokens.out}`);
229	
230	report.save(`${RESULTS}/report.md`);
231	report.saveTrace(`${RESULTS}/trace.json`, thing);
232	cp.done = true; cp.summary = report.summary(); saveCheckpoint(cp);
233	console.log(JSON.stringify(report.summary(), null, 2));
234	process.exit(report.passed ? 0 : 1);
