76	/** Every file under the pod fs root (paths only — `/api/fs/tree` returns `{files:[...]}`). */
77	async function lsFiles(pod, pathRx) {
78	  const { files } = await pod.fsTree().catch(() => ({ files: [] }));
79	  return (files ?? []).filter((f) => (pathRx ? pathRx.test(f) : true));
80	}
81	
82	/**
83	 * Paths that can NEVER count as proof a fixture was read.
84	 *
85	 * The session trace/snapshot is a verbatim record of the conversation — the model's own prose, the
86	 * raw attachment text, every yield argument. A fixture's token appears there whether or not the file
87	 * was ever understood, so "the token is in the trace" is EXACTLY the prose-grading this whole
88	 * campaign exists to forbid. `uploads/` is the fixture's own bytes sitting on disk — even more
89	 * circular.
90	 *
91	 * This was live: `Huchuypicchu` was scored a PASS against `latam/sessions/<id>/trace.json`, and
92	 * `2016-02-04` against `snapshot.json` + `uploads/<id>`. Both were worthless. Excluding these makes
93	 * two green ticks go red — which is the point: they were lies.
94	 */
95	const NOT_REAL_STATE = /(^|\/)(sessions|uploads)\/|\/(trace|snapshot)\.json$|^\.lmthing\/|sessions-ledger\.jsonl$/;
96	
97	/** Grep the CONTENT of the files whose path matches `pathRx`. The tree carries paths only, so a
98	 *  token check against the tree JSON proves nothing — the bytes must actually be read. */
99	async function grepFs(pod, contentRx, pathRx) {
100	  const hits = [];
101	  for (const f of await lsFiles(pod, pathRx)) {
102	    if (NOT_REAL_STATE.test(f)) continue; // a token in the trace proves nothing — see above
103	    const body = await pod.readFile(f).catch(() => null);
104	    const text = typeof body === 'string' ? body : (body?.content ?? '');
105	    if (text && contentRx.test(text)) hits.push(f);
106	  }
107	  return hits;
108	}
109	
110	/**
111	 * The text the user ACTUALLY READS. A reply is a JSX descriptor tree (Stack/Heading/Callout/Table),
112	 * so regexing its raw JSON both misses real prose (it lives in `children`/`props.rows`) and matches
113	 * on structural keys that are not words anyone said. Flatten to the rendered strings instead.
114	 */
115	const flattenDescriptor = (d) =>
116	  d == null ? '' :
117	  typeof d === 'string' ? d :
118	  Array.isArray(d) ? d.map(flattenDescriptor).join(' ') :
119	  typeof d === 'object'
120	    ? [d.props?.title, d.props?.text, d.props?.label,
121	       JSON.stringify(d.props?.pairs ?? ''), JSON.stringify(d.props?.rows ?? ''),
122	       flattenDescriptor(d.children)].filter(Boolean).join(' ')
123	    : String(d);
124	
125	/** Everything the user saw this turn, as plain text. */
126	const visibleText = (turn) =>
127	  (turn.displays ?? []).map(flattenDescriptor).join('\n') || flattenDescriptor(turn.lastText ?? turn.text);
128	
129	/** All rows of every table the app declares, as one object. */
130	async function allRows(pod, projectId) {
131	  const manifest = await pod.appManifest(projectId).catch(() => ({}));
132	  const names = (manifest?.tables ?? []).map((t) => (typeof t === 'string' ? t : t.name));
133	  const out = {};
134	  for (const n of names) out[n] = (await pod.appData(projectId, n).catch(() => ({ rows: [] }))).rows ?? [];
135	  return out;
136	}
137	
138	/** Find the one table whose name matches — tables are AGENT-named, so never hardcode one. */
139	const tableNamed = (rows, rx) => Object.keys(rows).find((n) => rx.test(n));
140	
141	/** A fixture is only proved by its unique token landing in a DB ROW or a SPACE FILE. */
142	async function assertTokenInState(report, pod, projectId, { fixture, token, pathRx = /./ }) {
143	  const rx = rxOf(token);
144	  const hits = [];
145	  const rows = await allRows(pod, projectId);
146	  for (const [name, rs] of Object.entries(rows)) {
147	    if (rs.some((r) => rx.test(JSON.stringify(r)))) hits.push(`db:${name}`);
148	  }
149	  if (!hits.length) {
150	    const files = await grepFs(pod, rx, pathRx);
151	    hits.push(...files.map((f) => `file:${f}`));
152	  }
153	  report.check(
154	    `${fixture}: its unique token "${token}" landed in REAL STATE (not prose)`,
155	    hits.length > 0,
156	    hits.length ? hits.slice(0, 4).join(', ') : 'NOT FOUND in any row or file — the bytes were never read',
157	  );
158	  return hits;
159	}
