161	/** Signed inbound, exactly as integration-demo's WebhookEmitterDef verifies it. */
162	function signedInbound(pod, path, body, secret, header = 'x-demo-signature') {
163	  const raw = typeof body === 'string' ? body : JSON.stringify(body);
164	  const sig = 'sha256=' + createHmac('sha256', secret).update(raw).digest('hex');
165	  return pod.inbound(path, raw, { [header]: sig });
