168	/**
169	 * A hook/emitter/tasklist runs HEADLESS, in its own session — its node_start/node_end/yield_resolved
170	 * events are not in THING's stream. Snapshot the session list, fire, then drain every session that
171	 * appeared (plus any that grew) so an Act can assert on what the tasklist actually DID.
172	 */
173	async function sessionIds(pod) {
174	  const l = await pod.req('GET', '/api/sessions').catch(() => ({ sessions: [] }));
175	  return (l.sessions ?? []).map((s) => s.sessionId);
176	}
177	async function drainSessions(pod, ids) {
178	  const events = [];
179	  for (const id of ids) {
180	    const r = await pod
181	      .req('GET', `/api/sessions/${id}/events?since=0&format=json`)
182	      .catch(() => ({ events: [] }));
183	    for (const e of r.events ?? []) events.push(e.event);
184	  }
185	  return events;
186	}
187	/** Fire `run()` and return every trace event of the headless work it kicked off. */
188	async function fireAndTrace(pod, run, { settleMs = 240_000, quietMs = 20_000 } = {}) {
189	  const before = new Set(await sessionIds(pod));
190	  const res = await run().catch((e) => ({ error: String(e) }));
191	  const t0 = now();
192	  let seen = new Set();
193	  let lastGrowth = now();
194	  let events = [];
195	  while (now() - t0 < settleMs) {
196	    await sleep(5_000);
197	    const ids = (await sessionIds(pod)).filter((i) => !before.has(i));
198	    for (const i of ids) seen.add(i);
199	    const drained = await drainSessions(pod, [...seen]);
200	    if (drained.length > events.length) lastGrowth = now();
201	    events = drained;
202	    const idle = await pod.req('GET', '/api/sessions').catch(() => ({ sessions: [] }));
203	    const busy = (idle.sessions ?? []).some((s) => seen.has(s.sessionId) && s.status !== 'idle');
204	    if (events.length && !busy && now() - lastGrowth > quietMs) break;
205	  }
206	  return { res, events, sessions: [...seen] };
207	}
