209	const yieldsOf = (evs, kind) => evs.filter((e) => e.type === 'yield' && e.kind === kind);
210	const resolvedOf = (evs, kind) => evs.filter((e) => e.type === 'yield_resolved' && e.kind === kind);
211	const nodeEnds = (evs) => evs.filter((e) => e.type === 'node_end');
212	const displaysOf = (evs) =>
213	  evs
214	    .filter((e) => e.type === 'display')
215	    .map((e) => {
216	      const d = e.descriptor;
217	      return typeof d === 'string' ? d : (d?.props?.text ?? d?.props?.children ?? JSON.stringify(d));
218	    })
219	    .map((s) => (typeof s === 'string' ? s : JSON.stringify(s)))
220	    .join('\n');
