25	    } catch (e) {
26	      const msg = `${e?.message ?? e} ${e?.cause?.code ?? ''} ${e?.cause?.message ?? ''}`;
27	      if (!TRANSIENT.test(msg) || attempt >= tries) throw e;
28	      await new Promise((r) => setTimeout(r, waitMs));
29	    }
30	  }
