1	/**
2	 * THING session driver — talks to a real agent session over the pod's HTTP API and gives a
3	 * scenario everything it needs to ASSERT on behaviour, not just on final text.
4	 *
5	 * Why HTTP and not the WebSocket the /chat SPA uses: the WS needs a dep and buys us nothing here.
6	 * The pod exposes the same surface over HTTP (sdk/org/libs/cli/src/server/web/agent-api.ts):
7	 *
8	 *   POST /api/sessions                      {projectId, agentSlug?, resumeSessionId?, budget?}
9	 *   POST /api/sessions/:id/message          {content}                         → 202
10	 *   GET  /api/sessions/:id/events?since=N&format=json                          → {events,lastSeq}
11	 *   GET  /api/sessions/:id/asks?format=json                                    → {asks}
12	 *   POST /api/sessions/:id/ask/:askId       {value}                            → answer a prompt
13	 *
14	 * The event stream is the full execution trace (sdk/org/libs/core/src/sandbox/trace.ts), so a
15	 * scenario can assert on the things that actually matter — which agents THING delegated to, which
16	 * consent-marked globals it called, which yields resolved, tokens burned, errors raised — instead
17	 * of grading a paragraph of prose.
18	 *
19	 * IMPORTANT (consent): the consent prompter is only wired for INTERACTIVE sessions
20	 * (session-manager.ts — `consentPrompter: args.interactive ? … : undefined`). A session created
21	 * through `POST /api/sessions` is interactive, so consent cards appear as asks here. Headless
22	 * paths (hooks, delegates, webhook dispatch) fail closed by design — that is a feature to assert,
23	 * not a bug to work around.
24	 */
25	
26	const sleep = (ms) => new Promise((r) => setTimeout(r, ms));
27	
28	export class ThingSession {
29	  /**
30	   * @param {import('./pod.mjs').Pod} pod
31	   * @param {object} opts
32	   * @param {string} [opts.projectId='user']   project to run in ('user' = the default project)
33	   * @param {string} [opts.agentSlug='thing']  THING is the default agent
34	   * @param {string} [opts.spaceRef]           bind to a project SPACE's agent (`<space>/<agent>`)
35	   *        instead of THING — the only way to exercise that specialist's OWN capability profile.
36	   * @param {(descriptor:object)=>unknown} [opts.onAsk]  answer asks (consent cards, forms).
37	   *        Return `undefined` to leave the ask open (the scenario answers it manually).
38	   * @param {boolean} [opts.verbose=false]     stream a live log to stdout
39	   */
40	  constructor(pod, opts = {}) {
41	    this.pod = pod;
42	    this.projectId = opts.projectId ?? 'user';
43	    this.agentSlug = opts.agentSlug ?? 'thing';
44	    this.spaceRef = opts.spaceRef;
45	    this.onAsk = opts.onAsk;
46	    this.verbose = opts.verbose ?? false;
47	    this.sessionId = null;
48	    /** every trace event seen, in order — the scenario's source of truth */
49	    this.events = [];
50	    /** asks the driver saw, with what it answered */
51	    this.asks = [];
52	    this.lastSeq = 0;
53	  }
54	
55	  log(...a) {
56	    if (this.verbose) console.log('[thing]', ...a);
57	  }
58	
59	  /** Create the session. Init is async pod-side — `send()` waits it out. */
60	  async start({ resumeSessionId, budget, spaceRef = this.spaceRef } = {}) {
61	    const body = {
62	      projectId: this.projectId,
63	      agentSlug: this.agentSlug,
64	      // Bind the session to a PROJECT SPACE's own agent (`<space>/<agent>`) instead of THING
65	      // (session-manager `_initProjectSession` → `parseSpaceRef`). This is what lets a scenario
66	      // probe one specialist's real capability profile directly, rather than inferring it from
67	      // what THING chose to delegate.
68	      ...(spaceRef ? { spaceRef } : {}),
69	      ...(resumeSessionId ? { resumeSessionId } : {}),
70	      ...(budget ? { budget } : {}),
71	    };
72	    const { sessionId } = await this.pod.req('POST', '/api/sessions', body);
73	    this.sessionId = sessionId;
74	    this.log('session', sessionId);
75	    return sessionId;
76	  }
77	
78	  /** Resume an existing session id (post-restart auto-resume scenario). */
79	  async resume(sessionId) {
80	    return this.start({ resumeSessionId: sessionId });
81	  }
82	
83	  /**
84	   * Fast-forward past a RESUMED session's existing trace without attributing it to the next turn.
85	   *
86	   * A scenario that runs Act-by-Act (`--acts=`) resumes the same session from a FRESH process, where
87	   * `lastSeq` starts at 0 — so the first `pullEvents()` replays the WHOLE session history and
88	   * `turn(startSeq)` folds it into the first turn's slice. Any assertion over that slice then reads
89	   * *earlier Acts'* displays: scenario 10 saw a restraint check "pass" on a build summary printed
90	   * two Acts ago. Call this right after `start()`/`resume()` so a turn's events are only its own.
91	   */
92	  async syncToTail() {
93	    for (let i = 0; i < 30; i++) {
94	      const before = this.lastSeq;
95	      await this.pullEvents();
96	      if (this.lastSeq === before) break;
97	      await sleep(200);
98	    }
99	    this.events.length = 0; // replayed history is not the next turn's work
100	    return this.lastSeq;
101	  }
102	
103	  /**
104	   * Pull new trace events since `lastSeq`.
105	   *
106	   * A long turn can spawn many delegate/headless sub-sessions; on a small pod (`maxSessions`) the
107	   * session manager may EVICT this top-level session shortly after its turn completes, so a poll
108	   * then 404s ("unknown session"). That is not a turn failure — the work already landed (assert it
109	   * on real pod state). So a 404 is surfaced as a soft signal (`this.sessionGone = true`) rather
110	   * than thrown; the settle loop treats it as turn-end once work has been seen.
111	   */
112	  async pullEvents() {
113	    let res;
114	    try {
115	      res = await this.pod.req('GET', `/api/sessions/${this.sessionId}/events?since=${this.lastSeq}&format=json`);
116	    } catch (err) {
117	      if (err?.status === 404) {
118	        this.sessionGone = true;
119	        return [];
120	      }
121	      throw err;
122	    }
123	    const { events, lastSeq } = res;
124	    for (const e of events ?? []) {
125	      this.events.push(e.event);
126	      if (this.verbose) this.#logEvent(e.event);
127	    }
128	    if (typeof lastSeq === 'number') this.lastSeq = lastSeq;
129	    return events ?? [];
130	  }
131	
132	  #logEvent(ev) {
133	    switch (ev.type) {
134	      case 'yield':
135	        this.log(`  yield ${ev.kind}`, JSON.stringify(ev.args)?.slice(0, 140));
136	        break;
137	      case 'display':
138	        this.log('  display', JSON.stringify(ev.descriptor)?.slice(0, 200));
139	        break;
140	      case 'node_start':
141	        this.log(`  node_start ${ev.kind} ${ev.label}`);
142	        break;
143	      case 'node_end':
144	        this.log(`  node_end ${ev.nodeId} ${ev.status} ${ev.durationMs}ms`);
145	        break;
146	      case 'eval_error':
147	      case 'typecheck_error':
148	        this.log(`  !! ${ev.type}: ${ev.message?.slice(0, 200)}`);
149	        break;
150	      default:
151	        break;
152	    }
153	  }
154	
155	  /** Open asks, with the raw descriptor (a ConsentCard is `descriptor.type === 'ConsentCard'`). */
156	  async openAsks() {
157	    const { asks } = await this.pod.req('GET', `/api/sessions/${this.sessionId}/asks?format=json`);
158	    return asks ?? [];
159	  }
160	
161	  /**
162	   * Answer an ask. Consent approval is anything in {true, 'approve', {approved:true},
163	   * {approve:true}} (core/src/globals/consent.ts `isConsentApproval`); ANYTHING else — including
164	   * null — is a denial.
165	   */
166	  async answerAsk(askId, value) {
167	    await this.pod.req('POST', `/api/sessions/${this.sessionId}/ask/${askId}`, { value });
168	    this.log('answered ask', askId, JSON.stringify(value));
169	  }
170	
171	  /**
172	   * Send a user message and wait for the turn to settle.
173	   *
174	   * "Settled" = the session is idle AND the trace has stopped growing for `quietMs`. We can't
175	   * key on a single `turn_end` because delegates/forks emit their own in sub-contexts; the
176	   * idle+quiet pair is the only reliable edge over HTTP.
177	   *
178	   * While waiting we drain asks through `onAsk` — that is how consent cards get approved mid-turn.
179	   * A turn blocked on an unanswered ask never goes idle, so an un-handled consent card surfaces as
180	   * a timeout with the ask still open (which the scenario can assert on).
181	   */
182	  /**
183	   * Ensure `this.sessionId` still exists; if it was evicted (`maxSessions` on a small pod), start a
184	   * fresh session — resuming the old id when the pod still has its snapshot, else a clean new one.
185	   * The project (its spaces, app, db) persists on disk regardless, so a re-established session still
186	   * sees everything built so far; only in-VM conversation memory is lost (acceptable — the scenario
187	   * drives self-contained follow-ups).
188	   */
189	  async #ensureAlive() {
190	    if (!this.sessionId) return;
191	    const list = await this.pod.req('GET', '/api/sessions').catch(() => ({ sessions: [] }));
192	    const alive = (list.sessions ?? []).some((s) => s.sessionId === this.sessionId);
193	    if (alive) return;
194	    this.log('session evicted — re-establishing');
195	    const prev = this.sessionId;
196	    try {
197	      await this.start({ resumeSessionId: prev });
198	    } catch {
199	      await this.start();
200	    }
201	    // The re-established session replays its whole persisted trace from seq 0. We ALREADY hold those
202	    // events, so appending the replay duplicates every past turn — and, worse, `turn(startSeq)` then
203	    // slices a window full of REPLAYED history and asserts on it as if it were the turn we just sent
204	    // (scenario 10 read a re-analysis of turn 1's images as the work of its "yes" turn). Drain the
205	    // replay to re-sync `lastSeq`, then discard it: it is history we already have.
206	    const held = this.events.length;
207	    this.lastSeq = 0;
208	    for (let i = 0; i < 30; i++) {
209	      const before = this.lastSeq;
210	      await this.pullEvents();
211	      if (this.lastSeq === before) break;
212	      await sleep(200);
213	    }
214	    this.events.length = held;
215	    this.sessionGone = false;
216	  }
