471	/** Approve every consent card; leave other asks for the scenario. */
472	export const approveAllConsent = (descriptor) =>
473	  descriptor?.type === 'ConsentCard' ? true : undefined;
474	/** Deny every consent card (for the denial branch of the consent scenario). */
475	export const denyAllConsent = (descriptor) =>
476	  descriptor?.type === 'ConsentCard' ? false : undefined;
