          try {
            await thing.resume(cp.sessionId);
            await thing.syncToTail();
            continue;
          } catch {
            /* fall through to a fresh session */
          }
        }
        cp.sessionId = await thing.start();
        await thing.syncToTail();
        saveCheckpoint(cp);
      }
    }
  };
