  }
  const anyFm = (rx) => Object.entries(nodes).filter(([, v]) => rx.test(v.fm)).map(([k]) => k);
  const hasForEach = anyFm(/^\s*forEach:/m);
  const hasDeps = anyFm(/^\s*dependsOn:\s*\[?\s*\w/m);
